const data = $input.first().json;

if (!data || !data.signals) {
  return [{
    json: {
      error: "No signals from parser",
      raw: data
    }
  }];
}

const findings = [];

// GTM-01: Missing GA4 Config Tag
if ((data.signals.ga4ConfigTagCount || 0) === 0) {
  findings.push({
    rule: "GTM-01",
    status: "FAIL",
    severity: "CRITICAL",
    issue: "No GA4 Config Tag found",
    evidence: "ga4ConfigTagCount = 0",
    root_cause: "[TAG] GA4 configuration missing",
    recommendation: "Create a GA4 Configuration tag and fire it on All Pages"
  });
}

// GTM-03: Orphaned Tags
for (const tag of (data.orphanedTags || [])) {
  findings.push({
    rule: "GTM-03",
    status: "FAIL",
    severity: "HIGH",
    issue: "Tag has no firing trigger",
    evidence: `${tag.name} (${tag.id})`,
    root_cause: "[GTM] Tag cannot fire",
    recommendation: `Assign a trigger to ${tag.name}`
  });
}

// GTM-04: Orphaned Triggers
for (const trigger of (data.orphanedTriggers || [])) {
  findings.push({
    rule: "GTM-04",
    status: "FAIL",
    severity: "LOW",
    issue: "Unused trigger",
    evidence: `${trigger.name} (${trigger.id})`,
    root_cause: "[GTM] Trigger not attached to any tag",
    recommendation: `Remove ${trigger.name}`
  });
}

// GTM-05: Unused Variables
for (const variable of (data.unusedVariables || [])) {
  findings.push({
    rule: "GTM-05",
    status: "FAIL",
    severity: "LOW",
    issue: "Unused variable",
    evidence: `${variable.name}`,
    root_cause: "[GTM] Variable not referenced",
    recommendation: `Remove ${variable.name}`
  });
}

// GTM-08: Excessive Custom HTML
if ((data.signals.customHtmlTagCount || 0) > 3) {
  findings.push({
    rule: "GTM-08",
    status: "FAIL",
    severity: "MEDIUM",
    issue: "Too many Custom HTML tags",
    evidence: `${data.signals.customHtmlTagCount} Custom HTML tags`,
    root_cause: "[TAG] Increased maintenance and security risk",
    recommendation: "Replace with native GTM templates where possible"
  });
}

return [{
  json: {
    container_name: data.container_name || "Unknown",
    container_id: data.container_id || "Unknown",

    findings_count: findings.length,

    total_tags: data.signals.totalTags || 0,
    total_triggers: data.signals.totalTriggers || 0,
    total_variables: data.signals.totalVariables || 0,

    signals: data.signals,
    findings: findings
  }
}];

const cv = $('HTTP Request').first().json.containerVersion;

if (!cv) {
  throw new Error('containerVersion not found');
}

const tags = (cv.tag || []).map(tag => {
  const params = {};

  (tag.parameter || []).forEach(p => {
    params[p.key] = p.value;
  });

  return {
    id: tag.tagId,
    name: tag.name,
    type: tag.type,
    params,
    trigger_ids: tag.firingTriggerId || [],
    folderId: tag.parentFolderId || null,
    isPaused: tag.paused || false,
    consentStatus: tag.consentSettings?.consentStatus || null
  };
});

const triggers = (cv.trigger || []).map(t => ({
  id: t.triggerId,
  name: t.name,
  type: t.type
}));

const variables = (cv.variable || []).map(v => ({
  id: v.variableId,
  name: v.name,
  type: v.type
}));
const ga4ConfigTags = tags.filter(
  t => ["gaawc", "googtag"].includes(t.type)
);
const ga4EventTags = tags.filter(t => t.type === 'gaawe');
const orphanedTags = tags.filter(
  t => t.trigger_ids.length === 0
);

const allFiringIds = new Set(
  tags.flatMap(t => t.trigger_ids)
);

const orphanedTriggers = triggers.filter(
  t => !allFiringIds.has(t.id)
);
const allParamValues = tags.flatMap(t => Object.values(t.params).map(String));
const unusedVariables = variables.filter(v => {
  // Skip ecommerce DLVs — referenced via object path not direct name
  if (v.name.startsWith("dlv-ecommerce")) return false;
  return !allParamValues.some(val => val.includes(v.name));
});


const ecomEvents = [
  'view_item',
  'view_item_list',
  'add_to_cart',
  'remove_from_cart',
  'view_cart',
  'begin_checkout',
  'add_payment_info',
  'purchase'
];

const ecommerceEventNames = ga4EventTags
  .map(t =>
    t.params.eventName ||
    t.params.event_name ||
    null
  )
  .filter(Boolean)
  .filter(e => ecomEvents.includes(e));

const pausedTags = tags.filter(
  t => t.isPaused
);

const consentNotSetTags = tags.filter(
  t =>
    !t.consentStatus ||
    t.consentStatus === 'NOT_SET'
);

return [{
  json: {
    container_name:
      cv.container?.name || 'unknown',

    container_id:
      cv.container?.publicId || 'unknown',

    signals: {
      totalTags: tags.length,
      totalTriggers: triggers.length,
      totalVariables: variables.length,

      ga4ConfigTagCount:
        ga4ConfigTags.length,

      ga4EventTagCount:
        ga4EventTags.length,

      duplicateGA4ConfigRisk:
        ga4ConfigTags.length > 1,

      orphanedTagCount:
        orphanedTags.length,

      orphanedTriggerCount:
        orphanedTriggers.length,

      unusedVariableCount:
        unusedVariables.length,

      pausedTagCount:
        pausedTags.length,

      customHtmlTagCount:
        tags.filter(
          t => t.type === 'html'
        ).length,

      consentNotSetCount:
        consentNotSetTags.length,

      ecommerceEventNames
    },

    orphanedTags:
      orphanedTags.map(t => ({
        id: t.id,
        name: t.name
      })),

    orphanedTriggers:
      orphanedTriggers.map(t => ({
        id: t.id,
        name: t.name
      })),

    unusedVariables:
      unusedVariables.map(v => ({
        id: v.id,
        name: v.name
      }))
  }
}];

